namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string Text { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public class DocumentSummarizationService
{
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SplitIntoSentences(text);

        if (sentences.Length <= maxSentences)
            return text.Trim();

        // Score sentences by word count and position (earlier sentences ranked higher)
        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Score = ScoreSentence(sentence, index, sentences.Length)
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => Array.IndexOf(sentences, s.Sentence))
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitIntoSentences(string text)
    {
        return text
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .Select(s => s + ".")
            .ToArray();
    }

    private static double ScoreSentence(string sentence, int index, int totalSentences)
    {
        var wordCount = sentence.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length;
        double positionScore = 1.0 - (double)index / totalSentences;
        double lengthScore = Math.Min(wordCount / 20.0, 1.0);
        return positionScore * 0.6 + lengthScore * 0.4;
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizeController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest(new { error = "Text field is required and cannot be empty." });

        var summary = _summarizationService.Summarize(request.Text, request.MaxSentences);

        var response = new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        };

        return Ok(response);
    }
}

